import{_ as t,o as a,c as n,at as s}from"./chunks/framework.D0_TLDYh.js";const u=JSON.parse('{"title":"ev-reth Overview","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"ev-reth Overview | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"ev-reth/overview.md","filePath":"ev-reth/overview.md","lastUpdated":1772446570000}'),r={name:"ev-reth/overview.md"};function i(o,e,l,h,p,c){return a(),n("div",null,e[0]||(e[0]=[s(`<h1 id="ev-reth-overview" tabindex="-1">ev-reth Overview <a class="header-anchor" href="#ev-reth-overview" aria-label="Permalink to &quot;ev-reth Overview&quot;">​</a></h1><p>ev-reth is a modified <a href="https://github.com/paradigmxyz/reth" target="_blank" rel="noreferrer">reth</a> Ethereum execution client optimized for Evolve rollups.</p><h2 id="what-is-ev-reth" tabindex="-1">What is ev-reth? <a class="header-anchor" href="#what-is-ev-reth" aria-label="Permalink to &quot;What is ev-reth?&quot;">​</a></h2><p>ev-reth extends reth with:</p><ul><li><strong>Engine API integration</strong> — Driven by ev-node for block production</li><li><strong>Rollup-specific features</strong> — Base fee redirect, deploy allowlist, custom precompiles</li><li><strong>Configurable chain parameters</strong> — Contract size limits, custom gas settings</li></ul><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────┐</span></span>
<span class="line"><span>│               ev-node                    │</span></span>
<span class="line"><span>│         (consensus + DA + P2P)          │</span></span>
<span class="line"><span>└─────────────────┬───────────────────────┘</span></span>
<span class="line"><span>                  │ Engine API</span></span>
<span class="line"><span>                  │ (JWT authenticated)</span></span>
<span class="line"><span>┌─────────────────▼───────────────────────┐</span></span>
<span class="line"><span>│               ev-reth                    │</span></span>
<span class="line"><span>│           (EVM execution)               │</span></span>
<span class="line"><span>│  ┌───────────┐  ┌───────────────────┐   │</span></span>
<span class="line"><span>│  │ State DB  │  │ Transaction Pool  │   │</span></span>
<span class="line"><span>│  └───────────┘  └───────────────────┘   │</span></span>
<span class="line"><span>│  ┌───────────────────────────────────┐  │</span></span>
<span class="line"><span>│  │          EVM + Precompiles        │  │</span></span>
<span class="line"><span>│  └───────────────────────────────────┘  │</span></span>
<span class="line"><span>└─────────────────────────────────────────┘</span></span></code></pre></div><p>ev-node drives ev-reth through the Engine API:</p><ol><li>ev-node calls <code>engine_forkchoiceUpdated</code> with payload attributes</li><li>ev-reth builds a block from pending transactions</li><li>ev-node calls <code>engine_getPayload</code> to retrieve the block</li><li>ev-node broadcasts and submits to DA</li><li>ev-node calls <code>engine_newPayload</code> to finalize</li></ol><h2 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td><a href="/ev-reth/features/base-fee-redirect">Base Fee Redirect</a></td><td>Send base fees to treasury instead of burning</td></tr><tr><td><a href="/ev-reth/features/deploy-allowlist">Deploy Allowlist</a></td><td>Restrict who can deploy contracts</td></tr><tr><td><a href="/ev-reth/features/contract-size-limits">Contract Size Limits</a></td><td>Increase max contract size beyond 24KB</td></tr><tr><td><a href="/ev-reth/features/mint-precompile">Mint Precompile</a></td><td>Native token minting for bridges</td></tr></tbody></table><h2 id="when-to-use-ev-reth" tabindex="-1">When to Use ev-reth <a class="header-anchor" href="#when-to-use-ev-reth" aria-label="Permalink to &quot;When to Use ev-reth&quot;">​</a></h2><p>Use ev-reth when you want:</p><ul><li>Full EVM compatibility</li><li>Ethereum tooling (Foundry, Hardhat, etc.)</li><li>Standard wallet support (MetaMask, etc.)</li><li>High-performance Rust execution</li></ul><h2 id="repository" tabindex="-1">Repository <a class="header-anchor" href="#repository" aria-label="Permalink to &quot;Repository&quot;">​</a></h2><ul><li>GitHub: <a href="https://github.com/evstack/ev-reth" target="_blank" rel="noreferrer">github.com/evstack/ev-reth</a></li><li>Based on: <a href="https://github.com/paradigmxyz/reth" target="_blank" rel="noreferrer">paradigmxyz/reth</a></li></ul><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/getting-started/evm/quickstart">EVM Quickstart</a> — Get started</li><li><a href="/ev-reth/configuration">Configuration</a> — Chainspec and settings</li><li><a href="/ev-reth/engine-api">Engine API</a> — How ev-node communicates with ev-reth</li></ul>`,18)]))}const v=t(r,[["render",i]]);export{u as __pageData,v as default};
